import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.encoder.Encode;

public class SecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handle user input by escaping it before including in HTML response
        try {
            PrintWriter out = new PrintWriter("index.html");
            out.println("<html>");
            out.println("<head><title>Secure Code</title></head>");
            out.println("<body>");
            out.println("<h1>Welcome, " + Encode.forHtml(userInput) + "</h1>"); // User input is properly escaped here
            out.println("</body>");
            out.println("</html>");
            out.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
